USE nln_lyrics;

SET NAMES utf8mb4;

INSERT INTO news (title, image, summary, content, artist_id, created_at) VALUES
(
  'Taylor Swift tiếp tục giữ nhiệt cho kỷ nguyên "The Life of a Showgirl"',
  '1766509623_taylor_swift.jpg',
  'Các tín hiệu gần nhất từ hệ sinh thái phát hành cho thấy Taylor Swift vẫn duy trì nhịp quan tâm quanh album "The Life of a Showgirl", thay vì chuyển sang một chiến dịch hoàn toàn mới.',
  'Ở thời điểm hiện tại, hoạt động đáng chú ý nhất của Taylor Swift vẫn xoay quanh dư âm từ "The Life of a Showgirl". Các trang phát hành, credit và biến thể liên quan đến kỷ nguyên này tiếp tục được cộng đồng theo dõi sát sao, cho thấy album vẫn đang là tâm điểm trong giai đoạn hậu phát hành. \n\nĐiều đáng nói là cách Taylor giữ nhiệt cho dự án không đi theo hướng ồn ào. Thay vào đó, cô để bản thân album tự tạo vòng đời thông qua thảo luận của người nghe, sức lan tỏa của các ca khúc nổi bật và sự chú ý dành cho phần hình ảnh nhận diện. Với một nghệ sĩ vốn quen kiểm soát từng thời kỳ âm nhạc như Taylor Swift, đây là một chiến lược khá nhất quán. \n\nTừ góc nhìn thị trường, việc tiếp tục duy trì sự hiện diện của "The Life of a Showgirl" giúp Taylor giữ vị thế ở cả mặt thương mại lẫn truyền thông, đồng thời mở ra dư địa cho những bước đi tiếp theo. Người hâm mộ hiện vẫn chờ xem liệu cô có bổ sung thêm phiên bản, MV hay các nội dung hậu trường mới cho kỷ nguyên này trong thời gian tới hay không.',
  1,
  NOW() - INTERVAL 5 DAY
),
(
  'Olivia Rodrigo mở rộng sức ảnh hưởng với chiến dịch thời trang mới',
  'olivia_rodrigo.jfif',
  'Olivia Rodrigo tiếp tục xuất hiện nổi bật trong không gian pop culture khi góp mặt trong chiến dịch thời trang lớn, qua đó giữ độ phủ hình ảnh trong lúc người hâm mộ chờ tín hiệu âm nhạc tiếp theo.',
  'Hoạt động mới nhất của Olivia Rodrigo cho thấy nữ ca sĩ đang duy trì hiện diện rất tốt ngoài âm nhạc. Việc góp mặt trong một chiến dịch thời trang quốc tế giúp Olivia tiếp tục củng cố hình ảnh của một gương mặt pop thế hệ mới, vừa có cá tính thẩm mỹ rõ rệt vừa giữ được kết nối mạnh với công chúng trẻ. \n\nĐiểm đáng chú ý là Olivia không đơn thuần xuất hiện với vai trò người mẫu quảng bá. Cách cô xuất hiện trong chiến dịch lần này vẫn gợi lại đúng tinh thần đã làm nên thương hiệu cá nhân: trực diện, trẻ trung, hơi nổi loạn nhưng vẫn có độ tinh tế đủ để mở rộng ra ngoài phạm vi thị trường âm nhạc. Điều đó giúp cô giữ nhịp quan tâm của truyền thông trong lúc chưa tung ra một đợt phát hành lớn mới. \n\nVới nền tảng đã tạo dựng từ "SOUR" và "GUTS", mọi hoạt động công khai của Olivia lúc này đều được nhìn như tín hiệu cho chặng tiếp theo. Dù chưa có xác nhận chính thức về dự án âm nhạc mới, việc liên tục giữ độ nhận diện cao là bước đi quan trọng để bảo toàn sức nóng của thương hiệu Olivia Rodrigo.',
  2,
  NOW() - INTERVAL 4 DAY
),
(
  'Ariana Grande được chờ đợi cho giai đoạn trở lại sân khấu sau "eternal sunshine"',
  'ariana_grande.webp',
  'Sau chu kỳ phát hành "eternal sunshine", Ariana Grande đang được truyền thông và người hâm mộ theo dõi sát cho khả năng trở lại mạnh hơn với các hoạt động biểu diễn trực tiếp.',
  'Trong số những tên tuổi pop lớn hiện nay, Ariana Grande là một trong những nghệ sĩ được nhắc đến nhiều nhất mỗi khi xuất hiện tín hiệu về biểu diễn trực tiếp. Sau khi "eternal sunshine" tạo được dấu ấn rõ rệt về hình ảnh lẫn thành tích thương mại, sự quan tâm lúc này dồn vào câu hỏi quen thuộc: khi nào Ariana sẽ trở lại sân khấu với một giai đoạn quảng bá quy mô lớn hơn. \n\nĐiểm đáng chú ý là Ariana đang ở vị trí khá đặc biệt. Cô không cần xuất hiện dày đặc để giữ độ nóng, nhưng mỗi lần có thêm một tín hiệu mới về lịch trình hay định hướng hoạt động, mức độ bàn luận lại tăng rất nhanh. Điều đó phản ánh sức hút bền vững của cô sau nhiều chu kỳ album liên tiếp và khả năng biến mỗi lần trở lại thành một sự kiện của thị trường pop. \n\nVới đà quan tâm hiện có, nếu Ariana thực sự bước vào giai đoạn sân khấu mới trong thời gian tới, "eternal sunshine" rất có thể sẽ còn kéo dài vòng đời ảnh hưởng hơn nữa. Ở thời điểm hiện tại, đây vẫn là một trong những kỷ nguyên được cộng đồng fan mong đợi phần tiếp theo nhiều nhất.',
  3,
  NOW() - INTERVAL 3 DAY
),
(
  'Adele giữ nhịp im lặng chọn lọc, nhưng sức hút vẫn không suy giảm',
  'adele.jfif',
  'Dù chưa công bố dự án âm nhạc hay tour diễn mới, Adele vẫn là cái tên duy trì sức nặng đặc biệt trên truyền thông nhờ khoảng lặng được kiểm soát chặt chẽ sau giai đoạn hoạt động dày đặc trước đó.',
  'Khác với nhiều nghệ sĩ pop luôn duy trì tần suất xuất hiện dày, Adele tiếp tục đi theo con đường quen thuộc: xuất hiện ít nhưng mỗi lần được nhắc đến đều tạo cảm giác có trọng lượng. Giai đoạn hiện tại chưa ghi nhận một chiến dịch album hay tour mới, song chính sự yên ắng đó lại làm tăng mức kỳ vọng của khán giả đối với bước đi kế tiếp của cô. \n\nSau những cột mốc lớn trong chu kỳ gần nhất, Adele dường như đang ưu tiên một khoảng nghỉ có chủ đích. Điều này không hề làm suy giảm sức nóng thương hiệu cá nhân; ngược lại, nó củng cố hình ảnh một nghệ sĩ chỉ lên tiếng khi thực sự có điều quan trọng để nói. Trong bối cảnh ngành công nghiệp âm nhạc vận hành với tốc độ ngày càng nhanh, cách Adele giữ nhịp xuất hiện như vậy vẫn là một trường hợp rất riêng. \n\nChính vì thế, dù chưa có xác nhận về dự án mới, Adele vẫn nằm trong nhóm nghệ sĩ được theo dõi nhất mỗi khi xuất hiện bất kỳ tín hiệu nào từ đội ngũ quản lý, sân khấu hay truyền thông quốc tế. Với một tên tuổi đã đạt tới độ nhận diện toàn cầu, đôi khi sự chờ đợi cũng là một phần trong chiến lược giữ sức hút.',
  4,
  NOW() - INTERVAL 2 DAY
),
(
  'Katy Perry tiếp tục kéo dài vòng đời của "143" trên nhiều mặt trận',
  'katy_perry.jfif',
  'Katy Perry vẫn duy trì nhịp quảng bá hậu phát hành cho "143", cho thấy dự án này chưa khép lại hoàn toàn trong chiến lược hiện diện của cô.',
  'Với Katy Perry, hoạt động gần đây cho thấy "143" vẫn là trung tâm trong giai đoạn hiện tại. Thay vì chuyển nhanh sang một chiến dịch mới, Katy tiếp tục kéo dài vòng đời của album bằng cách duy trì độ hiện diện của sản phẩm trên các kênh bán, nội dung quảng bá và các cuộc thảo luận xung quanh hình ảnh nhận diện của kỷ nguyên này. \n\nĐây là lựa chọn khá thực dụng trong bối cảnh thị trường pop hiện nay cạnh tranh rất mạnh. Một album không chỉ cần thời điểm phát hành, mà còn cần thời gian để xây dựng thêm vòng thảo luận mới, đặc biệt khi nghệ sĩ muốn tối ưu tác động thương mại và sức nhớ với công chúng đại chúng. Katy vốn là gương mặt giàu kinh nghiệm ở mảng pop radio, nên cách cô tiếp tục duy trì "143" là điều không quá bất ngờ. \n\nỞ chiều dài hơi hơn, việc kéo dài vòng đời của dự án hiện tại cũng giúp Katy giữ vị trí ổn định trong hệ sinh thái pop trước khi tính tới bước kế tiếp. Nếu trong thời gian tới cô tung thêm một nội dung mới gắn với "143" hoặc mở rộng sân khấu cho album này, mức độ quan tâm có thể sẽ còn tăng thêm.',
  5,
  NOW() - INTERVAL 1 DAY
);
